### Step 4: Implement Winning and Drawing Conditions

Finally, we need to check for win or draw conditions.

```python
class CheckersGame:
    def __init__(self):
        self.board = CheckersBoard()
        self.current_player = 'black'
        self.validator = MoveValidator(self.board)

    def switch_turn(self):
        if self.current_player == 'black':
            self.current_player = 'white'
        else:
            self.current_player = 'black'

    def make_move(self, start, end):
        if not self.validator.is_valid_move(start, end):
            print("Invalid move. Try again.")
            return False

        piece = self.board.board[start[0]][start[1]]
        self.board.board[end[0]][end[1]] = piece
        self.board.board[start[0]][start[1]] = None

        if (self.current_player == 'black' and end[0] == 7) or (self.current_player == 'white' and end[0] == 0):
            piece.king = True

        return True

    def check_winner(self):
        pieces_left = sum(1 for row in self.board.board for piece in row if piece and piece.color == self.current_player)
        if pieces_left == 0:
            if self.current_player == 'black':
                print("White wins!")
            else:
                print("Black wins!")
            return True

        # Check for draw (stalemate or no valid moves)
        valid_moves = []
        for row in range(8):
            for col in range(8):
                piece = self.board.board[row][col]
                if piece and piece.color == self.current_player:
                    for dr, dc in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        end_row, end_col = row + dr, col + dc
                        if (0 <= end_row < 8 and 0 <= end_col < 8) and self.validator.is_valid_move((row, col), (end_row, end_col)):
                            valid_moves.append(((row, col), (end_row, end_col)))
        if not valid_moves:
            print("Stalemate! It's a draw.")
            return True

        return False

# Example usage:
game = CheckersGame()
while not game.check_winner():
    start_pos = input("Enter the starting position (e.g., 2 3): ")
    end_pos = input("Enter the ending position (e.g., 4 5): ")
    start_pos = tuple(map(int, start_pos.split()))
    end_pos = tuple(map(int, end_pos.split()))
    if game.make_move(start_pos, end_pos):
        game.switch_turn()
        game.board.display()
```

